 497→/// POST /api/auth/reset removes all auth and subsequent requests pass through.
 498→#[cfg(feature = "web-ui")]
 499→#[tokio::test]
 500→async fn reset_auth_removes_all_authentication() {
 501→    let (addr, store) = start_auth_server().await;
 502→    store.set_initial_password("testpass123").await.unwrap();
 503→    let token = store.create_session().await.unwrap();
 504→
 505→    // Protected endpoint requires auth.
 506→    let resp = reqwest::get(format!("http://{addr}/api/bootstrap"))
 507→        .await
 508→        .unwrap();
 509→    assert_eq!(resp.status(), 401);
 510→
 511→    // Reset auth (requires session).
 512→    let client = reqwest::Client::new();
 513→    let resp = client
 514→        .post(format!("http://{addr}/api/auth/reset"))
 515→        .header("Cookie", format!("moltis_session={token}"))
 516→        .send()
 517→        .await
 518→        .unwrap();
 519→    assert_eq!(resp.status(), 200);
 520→
 521→    // Now auth is disabled, so middleware passes through.
 522→    let resp = reqwest::get(format!("http://{addr}/api/bootstrap"))
 523→        .await
 524→        .unwrap();
 525→    assert_eq!(resp.status(), 200);
 526→
 527→    // Auth-disabled mode should also bypass endpoint throttling.
 528→    for _ in 0..220 {
 529→        let resp = reqwest::get(format!("http://{addr}/api/bootstrap"))
 530→            .await
 531→            .unwrap();
 532→        assert_eq!(
 533→            resp.status(),
 534→            200,
 535→            "requests should not be rate-limited when auth is disabled"
 536→        );
 537→    }
 538→
 539→    // /api/auth/status should report authenticated: true, auth_disabled: true.
 540→    let resp = reqwest::get(format!("http://{addr}/api/auth/status"))
 541→        .await
 542→        .unwrap();
 543→    assert_eq!(resp.status(), 200);
 544→    let body: serde_json::Value = resp.json().await.unwrap();
 545→    assert_eq!(body["authenticated"], true);
 546→    assert_eq!(body["setup_required"], false);
 547→    assert_eq!(body["auth_disabled"], true);
 548→}
