 550→/// After resetting auth then re-setting up, auth_disabled is cleared.
 551→/// Reset generates a new setup code that must be provided.
 552→#[cfg(feature = "web-ui")]
 553→#[tokio::test]
 554→async fn reenable_auth_after_reset() {
 555→    let (addr, store, state) = start_auth_server_with_state().await;
 556→    store.set_initial_password("testpass123").await.unwrap();
 557→    let token = store.create_session().await.unwrap();
 558→
 559→    // Reset auth.
 560→    let client = reqwest::Client::new();
 561→    let resp = client
 562→        .post(format!("http://{addr}/api/auth/reset"))
 563→        .header("Cookie", format!("moltis_session={token}"))
 564→        .send()
 565→        .await
 566→        .unwrap();
 567→    assert_eq!(resp.status(), 200);
 568→
 569→    // Reset should have generated a new setup code.
 570→    let code = state
 571→        .inner
 572→        .read()
 573→        .await
 574→        .setup_code
 575→        .as_ref()
 576→        .unwrap()
 577→        .expose_secret()
 578→        .clone();
 579→
 580→    // Setup without code should fail.
 581→    let resp = client
 582→        .post(format!("http://{addr}/api/auth/setup"))
 583→        .header("Content-Type", "application/json")
 584→        .body(r#"{"password":"newpass123"}"#)
 585→        .send()
 586→        .await
 587→        .unwrap();
 588→    assert_eq!(resp.status(), 403);
 589→
 590→    // Re-enable: set up a new password with the correct setup code.
 591→    let resp = client
 592→        .post(format!("http://{addr}/api/auth/setup"))
 593→        .header("Content-Type", "application/json")
 594→        .body(format!(
 595→            r#"{{"password":"newpass123","setup_code":"{code}"}}"#
 596→        ))
 597→        .send()
 598→        .await
 599→        .unwrap();
 600→    assert_eq!(resp.status(), 200);
 601→
 602→    // Status should show auth_disabled: false, authenticated depends on cookie.
 603→    let resp = reqwest::get(format!("http://{addr}/api/auth/status"))
 604→        .await
 605→        .unwrap();
 606→    let body: serde_json::Value = resp.json().await.unwrap();
 607→    assert_eq!(body["auth_disabled"], false);
 608→    assert_eq!(body["setup_required"], false);
 609→
 610→    // Protected endpoints require auth again.
 611→    let resp = reqwest::get(format!("http://{addr}/api/bootstrap"))
 612→        .await
 613→        .unwrap();
 614→    assert_eq!(resp.status(), 401);
 615→}
