1143→            .post(format!("http://{addr}/api/auth/login"))
1144→            .header("Content-Type", "application/json")
1145→            .body(r#"{"password":"wrong-password"}"#)
1146→            .send()
1147→            .await
1148→            .unwrap();
1149→        assert_eq!(
1150→            resp.status(),
1151→            401,
1152→            "login should fail before throttle engages"
1153→        );
1154→    }
1155→
1156→    let throttled = client
1157→        .post(format!("http://{addr}/api/auth/login"))
1158→        .header("Content-Type", "application/json")
1159→        .body(r#"{"password":"wrong-password"}"#)
1160→        .send()
1161→        .await
1162→        .unwrap();
1163→
1164→    assert_eq!(throttled.status(), 429);
1165→
1166→    let retry_after = throttled
1167→        .headers()
1168→        .get(reqwest::header::RETRY_AFTER)
1169→        .and_then(|v| v.to_str().ok())
1170→        .and_then(|v| v.parse::<u64>().ok())
1171→        .unwrap_or(0);
1172→    assert!(
1173→        retry_after >= 1,
1174→        "expected Retry-After header on throttled login response"
1175→    );
1176→}
