1022→  1022→/// Login via /api/auth/login with a Host header containing a .localhost
1023→  1023→/// subdomain (e.g. moltis.localhost) should set Domain=localhost on the
1024→  1024→/// session cookie so the cookie is shared across all loopback hostnames.
1025→  1025→#[cfg(feature = "web-ui")]
1026→  1026→#[tokio::test]
1027→  1027→async fn login_cookie_includes_domain_for_localhost_subdomain() {
1028→  1028→    let (addr, store, _state) = start_localhost_server().await;
1029→  1029→    store.set_initial_password("testpass123").await.unwrap();
1030→  1030→
1031→  1031→    let client = reqwest::Client::builder()
1032→  1032→        .redirect(reqwest::redirect::Policy::none())
1033→  1033→        .build()
1034→  1034→        .unwrap();
1035→  1035→
1036→  1036→    let resp = client
1037→  1037→        .post(format!("http://{addr}/api/auth/login"))
1038→  1038→        .header("Host", "moltis.localhost:18080")
1039→  1039→        .header("Content-Type", "application/json")
1040→  1040→        .body(r#"{"password":"testpass123"}"#)
1041→  1041→        .send()
1042→  1042→        .await
1043→  1043→        .unwrap();
1044→  1044→    assert_eq!(resp.status(), 200, "login should succeed");
1045→  1045→
1046→  1046→    let cookie_header = resp
1047→  1047→        .headers()
1048→  1048→        .get("set-cookie")
1049→  1049→        .expect("login response must set a session cookie")
1050→  1050→        .to_str()
1051→  1051→        .unwrap();
1052→  1052→
1053→  1053→    assert!(
1054→  1054→        cookie_header.contains("Domain=localhost"),
1055→  1055→        "session cookie should include Domain=localhost for .localhost host, got: {cookie_header}"
1056→  1056→    );
