            .get(format!("http://{addr}/api/bootstrap"))
            .send()
            .await
            .unwrap();
        assert_eq!(
            resp.status(),
            401,
            "unauthenticated protected requests should pass through auth middleware before throttle engages"
        );
    }

    let throttled = client
        .get(format!("http://{addr}/api/bootstrap"))
        .send()
        .await
        .unwrap();

    assert_eq!(throttled.status(), 429);
}

