#![allow(clippy::unwrap_used, clippy::expect_used)]
//! Integration tests for the auth middleware protecting API endpoints.

use std::{
    net::SocketAddr,
    sync::{
        atomic::{AtomicBool, Ordering},
        Arc,
    },
};

use secrecy::ExposeSecret;

