                        path,
                        remote = %addr,
                        is_local,
                        has_bearer,
                        has_session_cookie,
                        "auth reject: unauthorized websocket connection"
                    );
                }
                (
                    StatusCode::UNAUTHORIZED,
                    Json(serde_json::json!({
                        "code": AUTH_NOT_AUTHENTICATED,
                        "error": "not authenticated"
                    })),
                )
                    .into_response()
            } else {
                Redirect::to("/login").into_response()
            }
